  "inlineSchema": "// Prisma Schema for BlackSheep CrossFit Application\n// This schema matches the existing TypeScript interfaces for seamless migration\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"./generated/client\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// User model - matches FitCenterUserProfile interface\nmodel User {\n  id        String   @id @default(cuid())\n  firstName String\n  lastName  String\n  email     String   @unique\n  phone     String?\n  role      String   @default(\"user\")\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Membership information stored as JSON to match existing structure\n  membership Json?\n\n  // Relations\n  classRegistrations ClassRegistration[]\n  membershipRenewals MembershipRenewal[]\n\n  @@index([email])\n  @@index([role])\n  @@map(\"users\")\n}\n\n// ClassSession model - matches ClassSession interface\nmodel ClassSession {\n  id                        String   @id @default(cuid())\n  organizationId            String\n  disciplineId              String\n  name                      String\n  dateTime                  DateTime\n  durationMinutes           Int\n  instructorId              String\n  capacity                  Int\n  registeredParticipantsIds String[]\n  waitlistParticipantsIds   String[]\n  status                    String   @default(\"scheduled\")\n  notes                     String?\n  isGenerated               Boolean  @default(false)\n  createdAt                 DateTime @default(now())\n  updatedAt                 DateTime @updatedAt\n\n  // Relations\n  discipline    Discipline          @relation(fields: [disciplineId], references: [id])\n  instructor    Instructor          @relation(fields: [instructorId], references: [id])\n  registrations ClassRegistration[]\n\n  @@index([dateTime])\n  @@index([disciplineId])\n  @@index([instructorId])\n  @@index([status])\n  @@index([organizationId])\n  @@map(\"class_sessions\")\n}\n\n// Discipline model - matches Discipline interface\nmodel Discipline {\n  id             String   @id @default(cuid())\n  organizationId String\n  name           String\n  description    String?\n  color          String   @default(\"#3b82f6\")\n  isActive       Boolean  @default(true)\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  // Schedule stored as JSON to match existing structure\n  schedule Json?\n\n  // Cancellation rules stored as JSON\n  cancellationRules Json?\n\n  // Relations\n  classes ClassSession[]\n\n  @@unique([organizationId, name])\n  @@index([isActive])\n  @@index([organizationId])\n  @@map(\"disciplines\")\n}\n\n// Instructor model - matches Instructor interface\nmodel Instructor {\n  id        String   @id @default(cuid())\n  firstName String\n  lastName  String\n  email     String   @unique\n  phone     String?\n  role      String   @default(\"instructor\")\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Additional instructor information stored as JSON\n  profile Json?\n\n  // Relations\n  classes ClassSession[]\n\n  @@index([email])\n  @@index([isActive])\n  @@index([role])\n  @@map(\"instructors\")\n}\n\n// MembershipPlan model - matches MembershipPlan interface\nmodel MembershipPlan {\n  id          String   @id @default(cuid())\n  name        String   @unique\n  description String?\n  price       Float\n  duration    Int // Duration in months\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Plan features and configuration stored as JSON\n  features Json?\n  config   Json?\n\n  @@index([isActive])\n  @@index([price])\n  @@map(\"membership_plans\")\n}\n\n// Organization model - for multi-tenant support\nmodel Organization {\n  id        String   @id @default(cuid())\n  name      String\n  settings  Json?\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"organizations\")\n}\n\n// ClassRegistration model - for tracking class registrations\nmodel ClassRegistration {\n  id           String    @id @default(cuid())\n  userId       String\n  classId      String\n  status       String    @default(\"registered\") // registered, waitlist, cancelled, attended, no_show\n  registeredAt DateTime  @default(now())\n  cancelledAt  DateTime?\n  notes        String?\n\n  // Relations\n  user  User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  class ClassSession @relation(fields: [classId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, classId])\n  @@index([userId])\n  @@index([classId])\n  @@index([status])\n  @@map(\"class_registrations\")\n}\n\n// MembershipRenewal model - for tracking membership renewals\nmodel MembershipRenewal {\n  id              String    @id @default(cuid())\n  userId          String\n  currentPlanId   String?\n  requestedPlanId String?\n  status          String    @default(\"pending\") // pending, approved, rejected, processed\n  requestedAt     DateTime  @default(now())\n  processedAt     DateTime?\n  notes           String?\n\n  // Renewal details stored as JSON\n  renewalDetails Json?\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([status])\n  @@index([requestedAt])\n  @@map(\"membership_renewals\")\n}\n\n// SystemLog model - for audit trail and monitoring\nmodel SystemLog {\n  id        String   @id @default(cuid())\n  level     String // debug, info, warn, error, fatal\n  message   String\n  context   Json?\n  timestamp DateTime @default(now())\n\n  // Additional metadata\n  operation String?\n  resource  String?\n  userId    String?\n  sessionId String?\n\n  @@index([level])\n  @@index([timestamp])\n  @@index([operation])\n  @@index([resource])\n  @@index([userId])\n  @@map(\"system_logs\")\n}\n\n// PerformanceMetric model - for performance monitoring\nmodel PerformanceMetric {\n  id          String   @id @default(cuid())\n  operation   String\n  resource    String\n  provider    String\n  duration    Int // Duration in milliseconds\n  success     Boolean\n  recordCount Int?\n  cacheHit    Boolean?\n  timestamp   DateTime @default(now())\n\n  // Additional metadata stored as JSON\n  metadata Json?\n\n  @@index([operation])\n  @@index([resource])\n  @@index([provider])\n  @@index([timestamp])\n  @@index([success])\n  @@map(\"performance_metrics\")\n}\n\n// Expense model - for tracking business expenses\nmodel Expense {\n  id        String   @id @default(cuid())\n  motivo    String // Reason for the expense\n  fecha     DateTime // Date of the expense\n  monto     Float // Amount spent\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([fecha])\n  @@index([createdAt])\n  @@map(\"expenses\")\n}\n\n// InAppAlert model - for in-app notifications\nmodel InAppAlert {\n  id        String   @id @default(cuid())\n  title     String\n  content   String\n  type      String // noticia, cancelacion, advertencia\n  startDate DateTime\n  endDate   DateTime\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([startDate, endDate])\n  @@map(\"in_app_alerts\")\n}\n",
